#include <stdio.h>
#include <math.h>

int main(void) {
    int n;
    double sum = 1.0;

    printf("Enter an integer n: ");
    scanf("%d", &n);

    for (int i = 2; i <= n; i++) {
        double numerator = 2 * i + 1;
        double denominator = i * i - 1;
        if (i % 2 == 0) {
            sum -= numerator / denominator;
        } else {
            sum += numerator / denominator;
        }
    }

    printf("%.3f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;

    // Read integer n
    scanf("%d", &n);

    // Generate expanding triangle pattern
    for (int i = 1; i <= n; ++i) {
        // Print leading spaces
        for (int j = n - i; j > 0; --j) {
            printf(" ");
        }

        // Print digits
        for (int k = 0; k < i; ++k) {
            printf("%d", i);
        }

        // Move to the next line
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <math.h>

int main(void) {
    double x[4], y[4];
    for (int i = 0; i < 4; i++) scanf("%lf %lf", &x[i], &y[i]);

    // Function to calculate the area of a triangle using Heron's formula
    double calculateArea(double a, double b, double c) {
        double s = (a + b + c) / 2;
        return sqrt(s * (s - a) * (s - b) * (s - c));
    }

    // Function to check if three points are collinear
    int areCollinear(double x1, double y1, double x2, double y2, double x3, double y3) {
        return (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) == 0;
    }

    // Generate all combinations of 3 points
    for (int i = 0; i < 4; i++) {
        for (int j = i + 1; j < 4; j++) {
            for (int k = j + 1; k < 4; k++) {
                double a = sqrt((x[i] - x[j]) * (x[i] - x[j]) + (y[i] - y[j]) * (y[i] - y[j]));
                double b = sqrt((x[j] - x[k]) * (x[j] - x[k]) + (y[j] - y[k]) * (y[j] - y[k]));
                double c = sqrt((x[k] - x[i]) * (x[k] - x[i]) + (y[k] - y[i]) * (y[k] - y[i]));

                if (!areCollinear(x[i], y[i], x[j], y[j], x[k], y[k])) {
                    double area = calculateArea(a, b, c);
                    printf("area %.3f\n", area);
                } else {
                    printf("collinear\n");
                }
            }
        }
    }

    return 0;
}

